mapper.select:
SELECT d.create_user as userId, MAX(u.name) as userName, COUNT(d.id) as caseCount, AVG(d.cs_score) as avgComplexity, AVG(d.uqs_score) as avgUqs, SUM(d.platform_actual_write_ms) / 3600000.0 as totalWriteHours FROM spotter_efficiency.case_metrics_detail d LEFT JOIN user u ON d.create_user COLLATE utf8mb4_general_ci = u.id WHERE 1=1
AND d.project_id = #{projectId}
AND d.create_time >= #{startTime}
AND d.create_time <= #{endTime}
GROUP BY d.create_user
